const menuItems = [{
  text: 'About',
  url: '/about'
}, {
  text: 'Services',
  url: '/services'
}, {
  text: 'Careers',
  url: '/careers'
}, {
  text: 'Blogs',
  url: '/blogs'
}, {
  text: 'Contact',
  url: '/contact'
}];
menuItems.forEach(({
  text,
  url
}) => {
  cy.contains('a', text).should('be.visible').click({
    force: true
  });
  cy.url().should('include', url);
  cy.go('back'); // Return to homepage for next test
});

cy.contains('a', 'Blogs').click();
cy.url().should('include', '/blogs');
// Verify blog posts (as of March 2026)
cy.contains('h2, h3', 'Rethinking Product Design with Intelligence').should('be.visible');
cy.contains('h2, h3', 'Architecture in the digital way').should('be.visible');
cy.contains('h2, h3', 'How Automative Brands Win Online').should('be.visible');
// Check read more links work
cy.contains('a', 'Read More').first().click();
cy.url().should('include', '/blogs/');
cy.go('back');

cy.contains('a', 'Contact').click();
cy.url().should('include', '/contact');
// Generic form check (site uses standard form fields)
cy.get('form').should('exist');
cy.get('input[type="text"], input[placeholder*="Name"]').should('exist');
cy.get('input[type="email"]').should('exist');
cy.get('textarea').should('exist');
cy.contains('button', 'Send').should('be.visible'); // or "Submit" - adjust if needed
// Optional: Fill & submit demo (intercepts to prevent real email)
cy.intercept('POST', '**/*contact*').as('submitForm');
cy.get('input[type="email"]').type('test@opsmonsters.com');
